# --- Helper Functions ---
def get_jwks():
    """Fetches and returns the JWKS from the OIDC provider."""
    try:
        jwks_response = requests.get(JWKS_URI)
        jwks_response.raise_for_status()
        return jwks_response.json()
    except requests.exceptions.RequestException as e:
        print(f"Error fetching JWKS: {e}")
        return None

def decode_and_verify_id_token(id_token):
    """
    Decodes and verifies the ID Token using the provider's JWKS.
    Assumes RS256 algorithm for simplicity.
    """
    jwks = get_jwks()
    if not jwks:
        return None

    try:
        # Get the header to find the key ID (kid)
        header = jwt.get_unverified_header(id_token)
        kid = header.get('kid')

        # Find the correct key in JWKS
        public_key = None
        for jwk in jwks['keys']:
            if jwk.get('kid') == kid:
                public_key = jwt.algorithms.RSAAlgorithm.from_jwk(json.dumps(jwk))
                break

        if not public_key:
            print(f"No matching public key found for kid: {kid}")
            return None

        # Decode and verify the token
        # audience (aud) must contain CLIENT_ID
        # issuer (iss) must match OIDC_PROVIDER_URL
        decoded_token = jwt.decode(
            id_token,
            public_key,
            algorithms=["RS256"], # Or whatever algorithm your provider uses
            audience=CLIENT_ID,
            issuer=oidc_config["issuer"],
            options={"verify_signature": True}
        )
        return decoded_token
    except jwt.exceptions.ExpiredSignatureError:
        print("ID Token has expired.")
        return None
    except jwt.exceptions.InvalidAudienceError:
        print(f"ID Token audience mismatch. Expected {CLIENT_ID}.")
        return None
    except jwt.exceptions.InvalidIssuerError:
        print(f"ID Token issuer mismatch. Expected {oidc_config['issuer']}.")
        return None
    except jwt.exceptions.InvalidSignatureError:
        print("ID Token signature is invalid.")
        return None
    except Exception as e:
        print(f"Error decoding or verifying ID Token: {e}")
        return None

